var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐아, 살짝 위험했다….","JPN":"ふえ、ちょっと危なかった……","ENG":"Phew, that was a bit dangerous...","TWN":"呼，剛剛有點危險…"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"살짝이 아니라 거의 두 동강이 날 뻔했지.","JPN":"ちょっとではなく、ほとんど真っ二つになる所だったな。","ENG":"A bit? You were almost cut in two.","TWN":"何止是有點，你差點斷成二半了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"후훗, 그래도 결과적으로는 잘 됐어요.","JPN":"ふふ、でも結果的にはオーケーです。","ENG":"Heh heh, but it all worked out well in the end.","TWN":"呵呵，以結果而言是好的啦。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"주변에 위험한 요소가 도사린다는 건 그만큼 귀한 보물이 있다는 뜻이니까요.","JPN":"周りに危険な要素がたくさんあるというのは、その分貴重なお宝があるということですから。","ENG":"The presence of danger can only mean the treasure is more valuable.","TWN":"寶藏的周圍總是充滿著危險。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"도움을 받은 대가로 보물을 찾으면 두 분에게도 조금은 나눠 드릴게요.","JPN":"助けてもらったお礼にお宝を探したら二人にも少し分けて差し上げましょう。","ENG":"Since you helped, I'll consider sharing the loot with you after finding the treasure.","TWN":"要是你們幫我找到寶藏，我會分給你們一點。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"원래는 너 혼자 꿀꺽할 생각이었다는 거네.","JPN":"本来ならあんたが独り占めするつもりだったということか。","ENG":"So you were going to have it all to yourself before, eh?","TWN":"看來你原本是打算一個人獨吞。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"신호가 점점 짧아지고 있네요.","JPN":"信号がどんどん短くなっています。","ENG":"The signal says we're getting closer.","TWN":"訊號越來越短了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"아마도 이쯤에 보물상자가…","JPN":"多分この辺に宝箱が……","ENG":"The treasure chest should be...","TWN":"看來寶箱就在…"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"앗, 찾았다!","JPN":"あっ、見つけた！","ENG":"Ah, found it!","TWN":"哇，找到了！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"와아, 21세기에 나무로 된 궤짝이라니. 얼마나 시대착오적인 거야?","JPN":"わあ、21世紀に木で作られた箱とは。どれだけ時代遅れなんだ？","ENG":"Wow, a wooden chest in the 21st century. Did we travel back in time or something?","TWN":"哇，竟然是21世紀的木箱，好有年代感。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐는 정말 낭만을 모르네요.","JPN":"ソーニャは本当にロマンを知らないのですね。","ENG":"Sonya, you really don't know what pirates are all about, do you?","TWN":"索妮雅真是一點也不浪漫。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"원래 진짜 귀한 보물은 초라한 나무 궤짝에 들어 있는 법이라고요.","JPN":"元々本当に貴重なお宝はしょぼい木の箱に入っているものなんです。","ENG":"Real treasure lies within unassuming wooden crates.","TWN":"真正的寶藏通常是在破舊的木箱裡找到的。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어라…?","JPN":"あれ……？","ENG":"Huh...?","TWN":"嗯…？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"뭐가 들어 있어?","JPN":"何が入っているんだ？","ENG":"What's inside?","TWN":"裡面有什麼？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"짧은 칼 한 자루요.","JPN":"短いナイフ一本です。","ENG":"Just one knife.","TWN":"一把短刀。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그게 들어 있는 전부라고?","JPN":"入っているのはそれで終わりか？","ENG":"That's all?","TWN":"就這樣？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫. 이래서야 나눠 갖기는 어렵겠군.","JPN":"ハハ。これでは分けるのは無理だ。","ENG":"Gah hah. Seems like it'll be difficult to share.","TWN":"哈哈哈，這恐怕不好分。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"보물지도라길래 설마 했는데…… 누가 장난친 모양이네.","JPN":"宝の地図というからまさかと思ったけど……誰かのいたずらだったようだな。","ENG":"The treasure map made it sound like there was going to be more... but I guess it was just a prank.","TWN":"還以為真是張藏寶圖…看來是某人的惡作劇。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그런데 이거…","JPN":"でもこれ……","ENG":"But this...","TWN":"但是這個…"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};